#include<bits/stdc++.h>
using namespace std;
const int N=1e5+10;
int b[N];
struct segment_tree
{
	struct node
	{
		int l,r,lazy,sum;
	}a[N*4];
	void pushup(int x)
	{
		a[x].sum=a[x<<1].sum+a[x<<1|1].sum;
	}
	void build(int x,int l,int r)
	{
		a[x].l=l;
		a[x].r=r;
		if(l==r)
		{
			a[x].sum=0;
			return;
		}
		int mid=(l+r)>>1;
		build(x<<1,l,mid);
		build(x<<1|1,mid+1,r);
	}
	void pushdown(int x)
	{
		if(a[x].lazy==1)
		{
			a[x<<1].lazy=(a[x<<1].lazy+1)%2;
			a[x<<1|1].lazy=(a[x<<1|1].lazy+1)%2;
			a[x].lazy=0;
			a[x].sum=(a[x].r-a[x].l+1)-a[x].sum;
		}
	}
	int query(int x,int l,int r)
	{
		if(a[x].l>=l&&a[x].r<=r)
		{
			if(a[x].lazy==1)
			{
				return (a[x].r-a[x].l+1)-a[x].sum;
			}
			return a[x].sum;
		}
		pushdown(x);
		int mid=(a[x].l+a[x].r)>>1;
		int ans=0;
		if(l<=mid)
		{
			ans=query(x<<1,l,r);
		}
		if(r>=mid+1)
		{
			ans+=query(x<<1|1,l,r);
		}
		return ans;
	}
	void update(int x,int l,int r)
	{
		if(a[x].l>=l&&a[x].r<=r)
		{
			a[x].lazy=(a[x].lazy+1)%2;
			return;
		}
		pushdown(x);
		int mid=(a[x].l+a[x].r)>>1;
		if(l<=mid)
		{
			update(x<<1,l,r);
		}
		if(r>=mid+1)
		{
			update(x<<1|1,l,r);
		}
		a[x].sum=query(x<<1,a[x].l,a[x].r)+query(x<<1|1,a[x].l,a[x].r);
	}
}t;
int main()
{
	int n,m;
	scanf("%d%d",&n,&m);
	t.build(1,1,n);
	while(m--)
	{
		int c,a,b;
		scanf("%d%d%d",&c,&a,&b);
		if(c==0)
		{
			t.update(1,a,b);
		}
		else
		{
			printf("%d\n",t.query(1,a,b));
		}
	}
	return 0;
}
